const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

const getSecret = async (secretName) => {
  if (process.env.NODE_ENV === 'production') {
    const { SecretManagerServiceClient } = require('@google-cloud/secret-manager');
    const client = new SecretManagerServiceClient();
    const projectId = process.env.GCP_PROJECT || process.env.GCLOUD_PROJECT;
    const name = `projects/${projectId}/secrets/${secretName}/versions/latest`;
    
    try {
      const [version] = await client.accessSecretVersion({ name });
      return version.payload.data.toString('utf8');
    } catch (error) {
      throw new Error(`Failed to retrieve secret ${secretName}: ${error.message}`);
    }
  } else {
    return process.env[secretName];
  }
};

const validateEmail = (email) => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

const validatePhoneNumber = (phone) => {
  const phoneRegex = /^\+?[1-9]\d{1,14}$/;
  return phoneRegex.test(phone.replace(/[\s\-\(\)]/g, ''));
};

const sanitizeInput = (input) => {
  if (typeof input !== 'string') {
    return input;
  }
  return input.replace(/[<>]/g, '');
};

const sendEmail = async (to, from, subject, text, html) => {
  const sendgridApiKey = await getSecret('SENDGRID_API_KEY');
  
  if (!sendgridApiKey) {
    throw new Error('SendGrid API key not configured');
  }

  if (!validateEmail(to)) {
    throw new Error('Invalid recipient email address');
  }

  if (!validateEmail(from)) {
    throw new Error('Invalid sender email address');
  }

  sgMail.setApiKey(sendgridApiKey);

  const msg = {
    to: to,
    from: from,
    subject: sanitizeInput(subject),
    text: sanitizeInput(text),
    html: html ? sanitizeInput(html) : undefined,
  };

  try {
    const response = await sgMail.send(msg);
    return {
      success: true,
      messageId: response[0].headers['x-message-id'],
      statusCode: response[0].statusCode
    };
  } catch (error) {
    throw new Error(`SendGrid error: ${error.message}`);
  }
};

const sendSMS = async (to, from, body) => {
  const twilioAccountSid = await getSecret('TWILIO_ACCOUNT_SID');
  const twilioAuthToken = await getSecret('TWILIO_AUTH_TOKEN');

  if (!twilioAccountSid || !twilioAuthToken) {
    throw new Error('Twilio credentials not configured');
  }

  if (!validatePhoneNumber(to)) {
    throw new Error('Invalid recipient phone number');
  }

  if (!validatePhoneNumber(from)) {
    throw new Error('Invalid sender phone number');
  }

  if (!body || body.length === 0) {
    throw new Error('SMS body cannot be empty');
  }

  if (body.length > 1600) {
    throw new Error('SMS body exceeds maximum length of 1600 characters');
  }

  const client = twilio(twilioAccountSid, twilioAuthToken);

  try {
    const message = await client.messages.create({
      body: sanitizeInput(body),
      from: from,
      to: to
    });

    return {
      success: true,
      messageSid: message.sid,
      status: message.status
    };
  } catch (error) {
    throw new Error(`Twilio error: ${error.message}`);
  }
};

exports.sendMessage = async (req, res) => {
  res.set('Access-Control-Allow-Origin', '*');
  
  if (req.method === 'OPTIONS') {
    res.set('Access-Control-Allow-Methods', 'POST');
    res.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
    res.set('Access-Control-Max-Age', '3600');
    return res.status(204).send('');
  }

  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const authHeader = req.get('Authorization');
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized: Missing or invalid authorization header' });
  }

  const token = authHeader.substring(7);
  const expectedToken = await getSecret('API_AUTH_TOKEN');
  
  if (token !== expectedToken) {
    return res.status(403).json({ error: 'Forbidden: Invalid token' });
  }

  const { type, email, sms } = req.body;

  if (!type || (type !== 'email' && type !== 'sms' && type !== 'both')) {
    return res.status(400).json({ error: 'Invalid message type. Must be "email", "sms", or "both"' });
  }

  const results = {};

  try {
    if (type === 'email' || type === 'both') {
      if (!email) {
        return res.status(400).json({ error: 'Email configuration is required' });
      }

      const { to, from, subject, text, html } = email;

      if (!to || !from || !subject || !text) {
        return res.status(400).json({ error: 'Missing required email fields: to, from, subject, text' });
      }

      results.email = await sendEmail(to, from, subject, text, html);
    }

    if (type === 'sms' || type === 'both') {
      if (!sms) {
        return res.status(400).json({ error: 'SMS configuration is required' });
      }

      const { to, from, body } = sms;

      if (!to || !from || !body) {
        return res.status(400).json({ error: 'Missing required SMS fields: to, from, body' });
      }

      results.sms = await sendSMS(to, from, body);
    }

    return res.status(200).json({
      success: true,
      results: results
    });

  } catch (error) {
    console.error('Error sending message:', error);
    return res.status(500).json({
      success: false,
      error: error.message
    });
  }
};

exports.sendEmail = sendEmail;
exports.sendSMS = sendSMS;